  ('fire-eq-eng-moex-00183', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防機關辦理建築物消防安全設備審查及查驗作業基準規定，消防設備師依「緊急電源容 量計算基準」核算供消防安全設備所須之緊急電源容量後，應以書面知會電機技師供納入整 合緊急發電系統設計容量考量，電機技師於接獲前揭消防用緊急電源容量計算結果資料，應 於幾日內確認有無影響建築整體緊急發電設備設計之虞，並以書面通知知會之消防設備師， 逾期未通知時視為無意見：', '["7", "14", "21", "30"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00184', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防設備人員執業執照登記辦法規定，消防設備人員受撤銷、廢止執業執照或停止執行業 務之處分者，應於處分送達次日起幾日內，將執業執照繳交原登記主管機關註銷或收存。逾 期未繳交者，由原登記主管機關公告註銷，並通知其所屬公會：', '["7", "15", "20", "30"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00185', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防安全設備設計監造測試及檢修作業辦法規定，同一案件之下列何種消防安全設備之監 造及測試，不得由同一執業機構或同一消防設備人員為之：', '["滅火器", "標示設備", "緊急照明燈", "室內消防栓"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00186', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防設備人員法規定，直轄市、縣（市）有登記執業之消防設備師達X人以上者，得組織 消防設備師公會；而消防設備師公會全國聯合會應由直轄市或縣（市）消防設備師公會Y個 單位以上之發起組織之。請問X+Y為何？', '["15", "16", "18", "20"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00187', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防設備人員法規定，消防設備人員執行業務之敘述，下列何者錯誤？', '["消防設備人員可單獨設立事務所或組織聯合事務所，且可設立分事務所，不以一處為限", "消防設備人員可受聘於依工程技術顧問公司管理條例許可及登記之工程技術顧問公司", "消防設備人員可受聘於依消防法規定應辦理消防安全設備檢修之場所", "消防設備人員以在同一執業機構執行業務為限；其執行業務區域及於全國"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00188', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防法施行細則規定，有關消防防護計畫應包括事項及施工中消防防護計畫報請備查日期 之敘述，下列何者錯誤？', '["消防防護計畫中之自衛消防編組：員工人數為30人，至少編組滅火班、通報班及避難引導班", "消防防護計畫中之防火避難設施之自行檢查：每月至少檢查1次", "消防防護計畫中之滅火、通報及避難訓練之實施；每半年至少應舉辦1次，每次不得少於 4小時", "施工中消防防護計畫，管理權人應於施工7日前報請施工場所所在地之直轄市、縣（市） 主管機關備查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00189', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防幫浦加壓送水裝置等及配管摩擦損失計算基準規定，幫浦之出水量在額定出水量之 A%時，其全揚程應達到額定出水量在性能曲線上全揚程之B%以上。下列A與B何者正確？', '["A=150，B=65", "A=140，B=70", "A=130，B=65", "A=120，B=60"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
